import 'package:flutter/widgets.dart';
import 'package:flutter_test/flutter_test.dart';

/// Pumps a bounded number of frames after building an accessibility test widget.
///
/// Several app surfaces intentionally keep animations/tickers active, so
/// [WidgetTester.pumpAndSettle] can time out even after the accessibility tree is
/// ready. This helper waits for the first rendered frames without requiring the
/// app to become completely idle.
Future<void> pumpAccessibilityTestFrames(WidgetTester tester) async {
  await tester.pump();
  await tester.pump(const Duration(milliseconds: 100));
}

Future<void> expectMeetsAccessibilityGuideline(
  WidgetTester tester,
  AccessibilityGuideline guideline,
) async {
  final handle = tester.ensureSemantics();
  try {
    await pumpAccessibilityTestFrames(tester);
    await expectLater(tester, meetsGuideline(guideline));
  } finally {
    handle.dispose();
    await disposeAccessibilityTestWidget(tester);
  }
}

Future<void> disposeAccessibilityTestWidget(WidgetTester tester) async {
  await tester.pump(const Duration(seconds: 3));
  await tester.pumpWidget(const SizedBox.shrink());
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/services/accessibility_service.dart';
import 'package:flutter_fractals/core/services/onboarding_service.dart';
import 'package:flutter_fractals/core/services/preset_store.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
import 'package:flutter_fractals/main.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:shared_preferences/shared_preferences.dart';

import 'permission_test_harness.dart';

class MainAppA11yHarness {
  late final PresetStore presetStore;
  late final AccessibilityService accessibilityService;
  late final RendererSettingsService rendererSettingsService;
  OnboardingService? onboardingService;

  Future<void> setUp({bool forceOnboarding = false}) async {
    TestWidgetsFlutterBinding.ensureInitialized();
    SharedPreferences.setMockInitialValues({});
    installDenyAllPermissionsHandler();
    presetStore = await PresetStore.create();
    accessibilityService = await AccessibilityService.create();
    rendererSettingsService = await RendererSettingsService.create();
    if (forceOnboarding) {
      onboardingService = await OnboardingService.create();
    }
  }

  Widget buildApp() {
    return FlutterFractalsApp(
      presetStore: presetStore,
      accessibilityService: accessibilityService,
      rendererSettingsService: rendererSettingsService,
      onboardingService: onboardingService,
      locale: const Locale('en'),
    );
  }
}

import 'package:permission_handler_platform_interface/permission_handler_platform_interface.dart';

class DenyAllPermissions extends PermissionHandlerPlatform {
  @override
  Future<Map<Permission, PermissionStatus>> requestPermissions(
    List<Permission> permissions,
  ) async {
    return {
      for (final p in permissions) p: PermissionStatus.denied,
    };
  }

  @override
  Future<PermissionStatus> checkPermissionStatus(Permission permission) async {
    return PermissionStatus.denied;
  }
}

void installDenyAllPermissionsHandler() {
  PermissionHandlerPlatform.instance = DenyAllPermissions();
}

